from collections import deque

def level_order(root):
    if not root:
        return []
    result = []
    queue = deque([root])
    while queue:
        level = []
        for _ in range(len(queue)):
            node = queue.popleft()
            level.append(node[0])
            if len(node) > 1 and node[1]:
                queue.append(node[1])
            if len(node) > 2 and node[2]:
                queue.append(node[2])
        result.append(level)
    return result

def find_circle_num(is_connected):
    n = len(is_connected)
    visited = [False] * n
    provinces = 0

    def dfs(city):
        visited[city] = True
        for neighbor in range(n):
            if is_connected[city][neighbor] == 1 and not visited[neighbor]:
                dfs(neighbor)

    for city in range(n):
        if not visited[city]:
            dfs(city)
            provinces += 1
    return provinces

