def exist(board, word):
    if not board:
        return False
    m, n = len(board), len(board[0])

    def dfs(r, c, i):
        if i == len(word):
            return True
        if r < 0 or c < 0 or r >= m or c >= n or board[r][c] != word[i]:
            return False
        board[r][c] = '#'
        found = dfs(r + 1, c, i + 1) or dfs(r - 1, c, i + 1) or dfs(r, c + 1, i + 1) or dfs(r, c - 1, i + 1)
        board[r][c] = word[i]
        return found

    for r in range(m):
        for c in range(n):
            if dfs(r, c, 0):
                return True
    return False

