from collections import deque

def right_side_view(root):
    if not root:
        return []
    result = []
    queue = deque([root])
    while queue:
        level_size = len(queue)
        for i in range(level_size):
            node = queue.popleft()
            if i == level_size - 1:
                result.append(node[0])
            if len(node) > 1 and node[1]:
                queue.append(node[1])
            if len(node) > 2 and node[2]:
                queue.append(node[2])
    return result

def count_good_nodes(root):
    def dfs(node, max_val):
        if not node:
            return 0
        is_good = 1 if node[0] >= max_val else 0
        new_max = max(max_val, node[0])
        left = dfs(node[1], new_max) if len(node) > 1 and node[1] else 0
        right = dfs(node[2], new_max) if len(node) > 2 and node[2] else 0
        return is_good + left + right
    return dfs(root, float('-inf'))

def rob_ii(nums):
    if len(nums) == 1:
        return nums[0]
    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

def rob_linear(nums):
    prev2, prev1 = 0, nums[0]
    for num in nums[1:]:
        prev2, prev1 = prev1, max(prev1, prev2 + num)
    return prev1

