    for right, char in enumerate(s):
        window[char] += 1
        if char in t_count and window[char] == t_count[char]:
            have += 1
        while have == need:
            if right - left + 1 < min_len:
                min_len = right - left + 1
                result = s[left:right + 1]
            window[s[left]] -= 1
            if s[left] in t_count and window[s[left]] < t_count[s[left]]:
                have -= 1
            left += 1
    return result

